// src/PrivacyPolicy.js

import React, { memo } from 'react';
import { motion } from 'framer-motion';

const itemAnim = { initial: { opacity: 0, y: 16 }, whileInView: { opacity: 1, y: 0 }, viewport: { once: true }, transition: { duration: 0.4 } };

const QrGridBackground = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden opacity-[0.03] dark:opacity-[0.05]">
    <div className="absolute inset-0 grid grid-cols-8" style={{ gridTemplateRows: 'repeat(4, 1fr)' }}>
      {Array.from({ length: 32 }).map((_, i) => (
        <div key={i} className="border border-purple-500"
          style={{ opacity: 0, animation: `qrCellPulse ${3 + (i % 4)}s ease-in-out ${(i * 0.08) % 3}s infinite` }} />
      ))}
    </div>
  </div>
));
QrGridBackground.displayName = 'QrGridBackground';

const Section = memo(({ title, children, delay = 0 }) => (
  <motion.div
    initial={{ opacity: 0, y: 16 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true }}
    transition={{ duration: 0.4, delay }}
    className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-8 space-y-3"
  >
    <h2 className="text-xl font-bold text-gray-900 dark:text-white">{title}</h2>
    {children}
  </motion.div>
));
Section.displayName = 'Section';

const PrivacyPolicy = memo(() => (
  <section className="relative min-h-screen bg-gray-50 dark:bg-[#0f0f1a] transition-colors duration-500 overflow-hidden">
    <QrGridBackground />
    <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden">
      <div className="absolute -top-40 left-1/2 -translate-x-1/2 w-[500px] h-[500px] rounded-full bg-purple-500/8 dark:bg-purple-500/10 blur-[110px]" />
    </div>

    <div className="relative z-10 max-w-3xl mx-auto px-6 md:px-12 py-24">

      {/* Header */}
      <motion.div {...itemAnim} className="mb-12 text-center">
        <p className="text-sm font-semibold uppercase tracking-widest text-purple-500 dark:text-purple-400 mb-3">
          Legal
        </p>
        <h1 className="text-4xl md:text-5xl font-extrabold text-gray-900 dark:text-white tracking-tight mb-4">
          Privacy Policy
        </h1>
        <div className="w-16 h-1 bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full mx-auto mb-4" />
        <p className="text-gray-400 dark:text-gray-500 text-sm">
          Last updated: March 24, 2026
        </p>
      </motion.div>

      {/* TL;DR banner */}
      <motion.div
        {...itemAnim}
        className="bg-purple-50 dark:bg-purple-900/20 border border-purple-200 dark:border-purple-500/20 rounded-2xl p-6 mb-8"
      >
        <p className="text-sm font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wide mb-2">
          ✦ TL;DR — The Short Version
        </p>
        <p className="text-gray-700 dark:text-gray-300 text-sm leading-relaxed">
          Qronetic collects <strong>absolutely no personal data</strong>. Everything runs in your browser. We have no accounts, no analytics on your content, no cookies, and no servers processing your QR codes. Your data never leaves your device.
        </p>
      </motion.div>

      <div className="space-y-6">

        <Section title="1. Information We Collect" delay={0}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            <strong className="text-gray-700 dark:text-gray-300">We collect nothing.</strong> Qronetic is a fully client-side application. All QR code generation and scanning happens entirely within your browser using JavaScript. No content you enter, generate, or scan is ever transmitted to any server.
          </p>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            We do not collect names, email addresses, IP addresses, device identifiers, or any other personally identifiable information.
          </p>
        </Section>

        <Section title="2. Local Storage" delay={0.05}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            Qronetic uses your browser's <strong className="text-gray-700 dark:text-gray-300">localStorage</strong> solely to save your QR code history and theme preference (light/dark mode) on your own device. This data:
          </p>
          <ul className="text-gray-500 dark:text-gray-400 text-sm space-y-2 pl-4">
            <li className="flex gap-2"><span className="text-purple-500">•</span> Never leaves your device</li>
            <li className="flex gap-2"><span className="text-purple-500">•</span> Is never transmitted to any server</li>
            <li className="flex gap-2"><span className="text-purple-500">•</span> Can be cleared at any time from your browser settings</li>
            <li className="flex gap-2"><span className="text-purple-500">•</span> Is not accessible to us in any way</li>
          </ul>
        </Section>

        <Section title="3. Cookies" delay={0.1}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            Qronetic does not use cookies of any kind — not for tracking, analytics, advertising, or session management. We have no need for them.
          </p>
        </Section>

        <Section title="4. Third-Party Services" delay={0.15}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            Qronetic uses the following third-party service:
          </p>
          <div className="bg-gray-50 dark:bg-[#0f0f1a] rounded-xl p-4 text-sm">
            <p className="font-semibold text-gray-700 dark:text-gray-300 mb-1">Web3Forms (Contact Form)</p>
            <p className="text-gray-500 dark:text-gray-400 leading-relaxed">
              When you submit the contact form, your name, email, and message are sent to Web3Forms to deliver your message to us. This is the only data we ever receive, and only when you voluntarily submit the contact form. See <a href="https://web3forms.com/privacy" target="_blank" rel="noopener noreferrer" className="text-purple-600 dark:text-purple-400 hover:underline">Web3Forms Privacy Policy</a>.
            </p>
          </div>
        </Section>

        <Section title="5. Analytics" delay={0.2}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            We do not use Google Analytics, Mixpanel, or any other analytics platform. We have no visibility into what QR codes you create, what content you scan, or how you use the tool. Zero.
          </p>
        </Section>

        <Section title="6. Camera Access" delay={0.25}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            The QR scanner feature requests access to your camera solely to scan QR codes in real time. Camera data is processed entirely within your browser using JavaScript — no images or video frames are ever uploaded or stored anywhere.
          </p>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            You can revoke camera permission at any time through your browser settings.
          </p>
        </Section>

        <Section title="7. Children's Privacy" delay={0.3}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            Since we collect no personal data whatsoever, Qronetic is safe for users of all ages. We have no mechanism to collect data from children or anyone else.
          </p>
        </Section>

        <Section title="8. Changes to This Policy" delay={0.35}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            If we ever change this policy, we will update the date at the top of this page. Given our no-data approach, significant changes are unlikely.
          </p>
        </Section>

        <Section title="9. Contact" delay={0.4}>
          <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
            Questions about this policy? Reach us at:
          </p>
          <a
            href="mailto:qronetic@gmail.com"
            className="inline-flex items-center gap-2 text-purple-600 dark:text-purple-400 hover:underline text-sm font-medium"
          >
            ✉ qronetic@gmail.com
          </a>
        </Section>

      </div>
    </div>
  </section>
));

PrivacyPolicy.displayName = 'PrivacyPolicy';
export default PrivacyPolicy;